  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Tableau des déploiements d'Aave sur de nouvelles chaînes</text>
  <g font-family="sans-serif">
    <rect x="20" y="50" width="205" height="150" rx="10" fill="#0f1a12" stroke="#4ade80" stroke-width="1.6"/>
